	@Test
	void noneIsolationAppliesEstimatorUpdatesAcrossSinkFlushes(@TempDir File dataDir) throws Exception {
		var vf = SimpleValueFactory.getInstance();
		var s = vf.createIRI("urn:s");
		var p = vf.createIRI("urn:p");
		var o = vf.createIRI("urn:o");

		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc"));
		store.init();
		try {
			LmdbSailStore backingStore = store.getBackingStore();
			SketchBasedJoinEstimator estimator = backingStore.getSketchBasedJoinEstimator();
			estimator.stop();
			estimator.setRebuildAllowedSupplier(() -> false);

			try (NotifyingSailConnection conn = store.getConnection()) {
				conn.begin(IsolationLevels.NONE);
				conn.addStatement(s, p, o);
				// Namespace updates use a different sink and trigger internal flushes in NONE transactions.
				conn.setNamespace("ex", "urn:example");
				conn.commit();
			}

			assertTrue(estimator.isReady(),
					"Estimator should receive queued updates even when NONE transactions flush through another sink");
		} finally {
			store.shutDown();
		}
	}

	@Test
	void commitSucceedsWhenLazyEstimatorSnapshotIsUnsupported(@TempDir File dataDir) throws Exception {
		var vf = SimpleValueFactory.getInstance();
		var s = vf.createIRI("urn:s");
		var p = vf.createIRI("urn:p");
		var o = vf.createIRI("urn:o");

		writeLegacySnapshot(dataDir.toPath().resolve(SNAPSHOT_FILE));

		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc"));
		store.init();
		try {
			try (NotifyingSailConnection conn = store.getConnection()) {
				conn.begin(IsolationLevels.SNAPSHOT_READ);
				conn.addStatement(s, p, o);
				assertDoesNotThrow(conn::commit,
						"Commit must succeed even if estimator state cannot be lazily loaded");
			}
		} finally {
			store.shutDown();
		}

		LmdbStore reopened = new LmdbStore(dataDir, new LmdbStoreConfig("spoc"));
		reopened.init();
		try {
			try (NotifyingSailConnection conn = reopened.getConnection()) {
				assertTrue(conn.hasStatement(s, p, o, false),
						"Committed data must remain visible after reopening the store");
			}
		} finally {
			reopened.shutDown();
		}
	}

	private static void setSketchBudgetBytes(SketchBasedJoinEstimator estimator, long minBytes, long maxBytes)
			throws Exception {
		Field minField = SketchBasedJoinEstimator.class.getDeclaredField("minSketchMemoryBytes");
		Field maxField = SketchBasedJoinEstimator.class.getDeclaredField("maxSketchMemoryBytes");
		minField.setAccessible(true);
		maxField.setAccessible(true);
		minField.setLong(estimator, minBytes);
		maxField.setLong(estimator, maxBytes);
	}

	private static void loadNameData(SailRepository repository) {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI name = vf.createIRI("urn:test:name");
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 0; i < 8; i++) {
				connection.add(vf.createIRI("urn:test:user:" + i), name, vf.createLiteral("u" + i));
			}
			connection.commit();
		}
	}

	private static void learnFilterPassRatio(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			try (var result = connection.prepareTupleQuery(QueryLanguage.SPARQL, LEARNED_FILTER_QUERY).evaluate()) {
				while (result.hasNext()) {
					result.next();
				}
			}
		}
	}

	private static Filter firstFilter(String query) {
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		Filter[] found = new Filter[1];
		parsed.getTupleExpr().visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Filter node) {
				if (found[0] == null) {
					found[0] = node;
				}
				super.meet(node);
			}
		});
		return found[0];
	}

	private static void writeLegacySnapshot(Path snapshot) throws Exception {
		Files.createDirectories(snapshot.getParent());
		try (DataOutputStream out = new DataOutputStream(Files.newOutputStream(snapshot))) {
			out.write(new byte[] { 'R', 'J', 'E', 'S' });
			out.writeByte(1);
		}
	}

	private static void loadManyStatements(LmdbStore store, int resourceCount) throws Exception {
		var vf = SimpleValueFactory.getInstance();
		IRI condition = vf.createIRI("http://example.com/theme/medical/Condition");
		IRI code = vf.createIRI("http://example.com/theme/medical/code");
		IRI patient = vf.createIRI("http://example.com/theme/medical/patient");
		try (NotifyingSailConnection conn = store.getConnection()) {
			conn.begin(IsolationLevels.NONE);
			for (int i = 0; i < resourceCount; i++) {
				var subject = vf.createIRI("urn:test:persist:condition:" + i);
				conn.addStatement(subject, org.eclipse.rdf4j.model.vocabulary.RDF.TYPE, condition);
				conn.addStatement(subject, code, vf.createLiteral("DX-" + i));
				conn.addStatement(subject, patient, vf.createIRI("urn:test:persist:patient:" + (i % 512)));
			}
			conn.commit();
		}
	}

	private static void forceRobustRebuildHeadroom(SketchBasedJoinEstimator estimator, long disableBytes,
			long enableBytes)
			throws Exception {
		putLongField(estimator, "robustRebuildDisableHeadroomBytes", disableBytes);
		putLongField(estimator, "robustRebuildEnableHeadroomBytes", enableBytes);
		putLongField(estimator, "robustRebuildGcProbeFloorBytes", enableBytes);
		putLongField(estimator, "robustRebuildRetryAfterNanos", 0L);
		putLongField(estimator, "lastRobustHeadroomGcNanos", 0L);
	}

	private static void forceAvailableHeapHeadroom(SketchBasedJoinEstimator estimator, long headroomBytes)
			throws Exception {
		putLongField(estimator, "debugAvailableHeapHeadroomOverrideBytes", headroomBytes);
	}

	private static long rebuildEpoch(SketchBasedJoinEstimator estimator) throws Exception {
		Field field = SketchBasedJoinEstimator.class.getDeclaredField("rebuildEpoch");
		field.setAccessible(true);
		return ((AtomicLong) field.get(estimator)).get();
	}

	private static void putLongField(Object target, String fieldName, long value) throws Exception {
		Field field = SketchBasedJoinEstimator.class.getDeclaredField(fieldName);
		field.setAccessible(true);
		unsafe().putLong(target, unsafe().objectFieldOffset(field), value);
	}

	private static Unsafe unsafe() throws Exception {
		Field field = Unsafe.class.getDeclaredField("theUnsafe");
		field.setAccessible(true);
		return (Unsafe) field.get(null);
	}
